typedef struct _json_value {
    struct _json_value *parent;

    json_type type;

    union {
        int boolean;
        json_int_t integer;
        double dbl;

        struct {
            unsigned int length;
            json_char *ptr;      /* null terminated */
        } string;

        struct {
            unsigned int length;

            struct {
